import React, { useEffect, useState } from 'react';
import axios from 'axios';

const InventoryList = () => {
    const [inventory, setInventory] = useState([]);
    const [loading, setLoading] = useState(true);
    const [search, setSearch] = useState('');
    const [statusFilter, setStatusFilter] = useState('');
    const [page, setPage] = useState(1);
    const [totalPages, setTotalPages] = useState(1);
    const [sortField, setSortField] = useState('');
    const [sortOrder, setSortOrder] = useState('asc');
    const [selectedItems, setSelectedItems] = useState([]);
    const [showBulk, setShowBulk] = useState(false);
    const [bulkAction, setBulkAction] = useState('');
    const [importFile, setImportFile] = useState(null);
    const [formData, setFormData] = useState({
        inventory_id: '',
        item_type: '',
        brand: '',
        model: '',
        component: '',
        qty: 1,
        details: '',
        socket_or_interface: '',
        status: 'AVAILABLE',
        used_in: '',
        ownership: 'INVENTORY',
        test_status: 'UNTESTED',
        cooler_required: '',
        notes: '',
        photo_refs: '',
        price_paid: '',
        source: '',
        seller: '',
        location_bin: '',
        location_shelf: '',
        location_notes: ''
    });

    const fetchInventory = async () => {
        setLoading(true);
        try {
            const response = await axios.get('http://localhost:5000/api/inventory', {
                params: { search, status: statusFilter, page, per_page: 10, sort: sortField, order: sortOrder }
            });
            setInventory(response.data.items);
            setTotalPages(response.data.pages);
        } catch (error) {
            console.error(error);
        }
        setLoading(false);
    };

    useEffect(() => {
        fetchInventory();
    }, [search, statusFilter, page]);

    const handleFormSubmit = async (e) => {
        e.preventDefault();
        try {
            if (editingItem) {
                await axios.put(`http://localhost:5000/api/inventory/${editingItem.id}`, formData);
            } else {
                await axios.post('http://localhost:5000/api/inventory', formData);
            }
            fetchInventory();
            setShowForm(false);
            setEditingItem(null);
            resetForm();
        } catch (error) {
            console.error(error);
        }
    };

    const handleEdit = (item) => {
        setEditingItem(item);
        setFormData({ ...item });
        setShowForm(true);
    };

    const handleSort = (field) => {
        const order = sortField === field && sortOrder === 'asc' ? 'desc' : 'asc';
        setSortField(field);
        setSortOrder(order);
        setPage(1);
        fetchInventory();
    };

    const handleSelectItem = (id) => {
        setSelectedItems(prev => prev.includes(id) ? prev.filter(i => i !== id) : [...prev, id]);
    };

    const handleBulkAction = async () => {
        if (!bulkAction || selectedItems.length === 0) return;
        try {
            if (bulkAction === 'delete') {
                await Promise.all(selectedItems.map(id => axios.delete(`http://localhost:5000/api/inventory/${id}`)));
                alert('Selected items deleted');
            } else if (bulkAction === 'update') {
                // For simplicity, update status to 'IN USE'
                await Promise.all(selectedItems.map(id => axios.put(`http://localhost:5000/api/inventory/${id}`, { status: 'IN USE' })));
                alert('Selected items updated');
            }
            setSelectedItems([]);
            setShowBulk(false);
            fetchInventory();
        } catch (error) {
            console.error(error);
        }
    };

    const exportToCSV = () => {
        const headers = ['inventory_id', 'item_type', 'brand', 'model', 'qty', 'status', 'details'];
        const csvContent = [headers.join(',')].concat(
            inventory.map(item => [
                item.inventory_id,
                item.item_type,
                item.brand,
                item.model,
                item.qty,
                item.status,
                `"${item.details}"`
            ].join(','))
        ).join('\n');
        const blob = new Blob([csvContent], { type: 'text/csv' });
        const url = URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'inventory_export.csv';
        a.click();
        URL.revokeObjectURL(url);
    };

    const handleImport = async (e) => {
        e.preventDefault();
        if (!importFile) return;
        const text = await importFile.text();
        const lines = text.split('\n').filter(line => line.trim());
        const headers = lines[0].split(',');
        const data = lines.slice(1).map(line => {
            const values = line.split(',');
            return headers.reduce((obj, header, i) => {
                obj[header.trim()] = values[i]?.trim() || '';
                return obj;
            }, {});
        });
        try {
            await Promise.all(data.map(item => axios.post('http://localhost:5000/api/inventory', item)));
            alert('Data imported successfully');
            fetchInventory();
        } catch (error) {
            console.error(error);
        }
    };

    const handleDelete = async (id) => {
        if (window.confirm('Are you sure you want to delete this item?')) {
            try {
                await axios.delete(`http://localhost:5000/api/inventory/${id}`);
                fetchInventory();
            } catch (error) {
                console.error(error);
            }
        }
    };

    const resetForm = () => {
        setFormData({
            inventory_id: '',
            item_type: '',
            brand: '',
            model: '',
            component: '',
            qty: 1,
            details: '',
            socket_or_interface: '',
            status: 'AVAILABLE',
            used_in: '',
            ownership: 'INVENTORY',
            test_status: 'UNTESTED',
            cooler_required: '',
            notes: '',
            photo_refs: '',
            price_paid: '',
            source: '',
            seller: '',
            location_bin: '',
            location_shelf: '',
            location_notes: ''
        });
    };

    const handleInputChange = (e) => {
        const { name, value } = e.target;
        setFormData({ ...formData, [name]: value });
    };

    return (
        <div className="container mx-auto p-4">
            <h1 className="text-3xl font-bold mb-4">Inventory Management</h1>

            {/* Search and Filter */}
            <div className="mb-4 flex flex-wrap gap-4">
                <input
                    type="text"
                    placeholder="Search by brand, model, type, or details..."
                    value={search}
                    onChange={(e) => setSearch(e.target.value)}
                    className="border p-2 rounded w-full md:w-1/3"
                />
                <select
                    value={statusFilter}
                    onChange={(e) => setStatusFilter(e.target.value)}
                    className="border p-2 rounded"
                >
                    <option value="">All Statuses</option>
                    <option value="AVAILABLE">Available</option>
                    <option value="IN USE">In Use</option>
                    <option value="UNTESTED">Untested</option>
                </select>
                <button
                    onClick={() => { setShowForm(true); setEditingItem(null); resetForm(); }}
                    className="bg-blue-500 text-white px-4 py-2 rounded hover:bg-blue-600"
                >
                    Add New Item
                </button>
                <button
                    onClick={exportToCSV}
                    className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600 ml-2"
                >
                    Export to CSV
                </button>
                <form onSubmit={handleImport} className="ml-2 inline">
                    <input
                        type="file"
                        accept=".csv"
                        onChange={(e) => setImportFile(e.target.files[0])}
                        className="mr-2"
                    />
                    <button type="submit" className="bg-purple-500 text-white px-4 py-2 rounded hover:bg-purple-600">
                        Import CSV
                    </button>
                </form>
                {selectedItems.length > 0 && (
                    <div className="ml-2 inline">
                        <select value={bulkAction} onChange={(e) => setBulkAction(e.target.value)} className="border p-1 rounded mr-2">
                            <option value="">Bulk Action</option>
                            <option value="update">Update Status to In Use</option>
                            <option value="delete">Delete</option>
                        </select>
                        <button onClick={handleBulkAction} className="bg-red-500 text-white px-4 py-2 rounded hover:bg-red-600">
                            Apply
                        </button>
                    </div>
                )}
            </div>

            {/* Form Modal */}
            {showForm && (
                <div className="fixed inset-0 bg-gray-600 bg-opacity-50 flex justify-center items-center">
                    <div className="bg-white p-6 rounded shadow-lg w-full max-w-lg max-h-screen overflow-y-auto">
                        <h2 className="text-xl font-bold mb-4">{editingItem ? 'Edit Item' : 'Add New Item'}</h2>
                        <form onSubmit={handleFormSubmit} className="space-y-4">
                            <input name="inventory_id" value={formData.inventory_id} onChange={handleInputChange} placeholder="Inventory ID" required className="w-full border p-2 rounded" />
                            <input name="item_type" value={formData.item_type} onChange={handleInputChange} placeholder="Item Type" className="w-full border p-2 rounded" />
                            <input name="brand" value={formData.brand} onChange={handleInputChange} placeholder="Brand" className="w-full border p-2 rounded" />
                            <input name="model" value={formData.model} onChange={handleInputChange} placeholder="Model" className="w-full border p-2 rounded" />
                            <input name="component" value={formData.component} onChange={handleInputChange} placeholder="Component" className="w-full border p-2 rounded" />
                            <input name="qty" type="number" value={formData.qty} onChange={handleInputChange} placeholder="Quantity" className="w-full border p-2 rounded" />
                            <textarea name="details" value={formData.details} onChange={handleInputChange} placeholder="Details" className="w-full border p-2 rounded"></textarea>
                            <input name="socket_or_interface" value={formData.socket_or_interface} onChange={handleInputChange} placeholder="Socket/Interface" className="w-full border p-2 rounded" />
                            <select name="status" value={formData.status} onChange={handleInputChange} className="w-full border p-2 rounded">
                                <option value="AVAILABLE">Available</option>
                                <option value="IN USE">In Use</option>
                                <option value="UNTESTED">Untested</option>
                            </select>
                            <input name="used_in" value={formData.used_in} onChange={handleInputChange} placeholder="Used In" className="w-full border p-2 rounded" />
                            <input name="ownership" value={formData.ownership} onChange={handleInputChange} placeholder="Ownership" className="w-full border p-2 rounded" />
                            <input name="test_status" value={formData.test_status} onChange={handleInputChange} placeholder="Test Status" className="w-full border p-2 rounded" />
                            <input name="cooler_required" value={formData.cooler_required} onChange={handleInputChange} placeholder="Cooler Required" className="w-full border p-2 rounded" />
                            <textarea name="notes" value={formData.notes} onChange={handleInputChange} placeholder="Notes" className="w-full border p-2 rounded"></textarea>
                            <input name="photo_refs" value={formData.photo_refs} onChange={handleInputChange} placeholder="Photo Refs" className="w-full border p-2 rounded" />
                            <input name="price_paid" type="number" step="0.01" value={formData.price_paid} onChange={handleInputChange} placeholder="Price Paid" className="w-full border p-2 rounded" />
                            <input name="source" value={formData.source} onChange={handleInputChange} placeholder="Source" className="w-full border p-2 rounded" />
                            <input name="seller" value={formData.seller} onChange={handleInputChange} placeholder="Seller" className="w-full border p-2 rounded" />
                            <input name="location_bin" value={formData.location_bin} onChange={handleInputChange} placeholder="Location Bin" className="w-full border p-2 rounded" />
                            <input name="location_shelf" value={formData.location_shelf} onChange={handleInputChange} placeholder="Location Shelf" className="w-full border p-2 rounded" />
                            <textarea name="location_notes" value={formData.location_notes} onChange={handleInputChange} placeholder="Location Notes" className="w-full border p-2 rounded"></textarea>
                            <div className="flex justify-end space-x-2">
                                <button type="button" onClick={() => { setShowForm(false); setEditingItem(null); }} className="bg-gray-500 text-white px-4 py-2 rounded">Cancel</button>
                                <button type="submit" className="bg-green-500 text-white px-4 py-2 rounded hover:bg-green-600">Save</button>
                            </div>
                        </form>
                    </div>
                </div>
            )}

            {/* Table */}
            {loading ? (
                <p>Loading...</p>
            ) : (
                <>
                    <div className="overflow-x-auto">
                        <table className="min-w-full bg-white border border-gray-300">
                            <thead>
                                <tr className="bg-gray-100">
                                    <th className="py-2 px-4 border">
                                        <input
                                            type="checkbox"
                                            onChange={(e) => {
                                                if (e.target.checked) {
                                                    setSelectedItems(inventory.map(item => item.id));
                                                } else {
                                                    setSelectedItems([]);
                                                }
                                            }}
                                            checked={selectedItems.length === inventory.length && inventory.length > 0}
                                        />
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('inventory_id')}>
                                        Inventory ID {sortField === 'inventory_id' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('item_type')}>
                                        Item Type {sortField === 'item_type' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('brand')}>
                                        Brand {sortField === 'brand' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('model')}>
                                        Model {sortField === 'model' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('qty')}>
                                        Qty {sortField === 'qty' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border cursor-pointer" onClick={() => handleSort('status')}>
                                        Status {sortField === 'status' && (sortOrder === 'asc' ? '↑' : '↓')}
                                    </th>
                                    <th className="py-2 px-4 border">Details</th>
                                    <th className="py-2 px-4 border">Actions</th>
                                </tr>
                            </thead>
                            <tbody>
                                {inventory.map(item => (
                                    <tr key={item.id} className={`hover:bg-gray-50 ${item.qty < 2 ? 'bg-red-100' : ''}`}>
                                        <td className="py-2 px-4 border">
                                            <input
                                                type="checkbox"
                                                checked={selectedItems.includes(item.id)}
                                                onChange={() => handleSelectItem(item.id)}
                                            />
                                        </td>
                                        <td className="py-2 px-4 border">{item.inventory_id}</td>
                                        <td className="py-2 px-4 border">{item.item_type}</td>
                                        <td className="py-2 px-4 border">{item.brand}</td>
                                        <td className="py-2 px-4 border">{item.model}</td>
                                        <td className="py-2 px-4 border">{item.qty}</td>
                                        <td className="py-2 px-4 border">{item.status}</td>
                                        <td className="py-2 px-4 border">{item.details}</td>
                                        <td className="py-2 px-4 border space-x-2">
                                            <button onClick={() => handleEdit(item)} className="bg-yellow-500 text-white px-2 py-1 rounded hover:bg-yellow-600">Edit</button>
                                            <button onClick={() => handleDelete(item.id)} className="bg-red-500 text-white px-2 py-1 rounded hover:bg-red-600">Delete</button>
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>

                    {/* Pagination */}
                    <div className="mt-4 flex justify-center space-x-2">
                        <button
                            onClick={() => setPage(page - 1)}
                            disabled={page === 1}
                            className="bg-blue-500 text-white px-4 py-2 rounded disabled:bg-gray-300"
                        >
                            Previous
                        </button>
                        <span className="px-4 py-2">Page {page} of {totalPages}</span>
                        <button
                            onClick={() => setPage(page + 1)}
                            disabled={page === totalPages}
                            className="bg-blue-500 text-white px-4 py-2 rounded disabled:bg-gray-300"
                        >
                            Next
                        </button>
                    </div>
                </>
            )}
        </div>
    );
};

export default InventoryList;
